# Principles can conflict. Example: a harmful but honest response vs
# a safe but misleading one. Resolution depends on principle hierarchy.

PRINCIPLE_HIERARCHY = ['harm', 'honesty', 'ethics', 'helpfulness']

def resolve_principle_conflict(
    results: dict,   # {principle.id: 'A' | 'B'}
    constitution: list = CONSTITUTION,
) -> str:
    """
    When principles disagree on which response is better,
    follow the hierarchy: harm > honesty > ethics > helpfulness.
    """
    by_category = {}
    for principle in constitution:
        if principle.id in results:
            cat = principle.category
            by_category.setdefault(cat, []).append(results[principle.id])

    for category in PRINCIPLE_HIERARCHY:
        votes = by_category.get(category, [])
        if not votes:
            continue
        from collections import Counter
        winner = Counter(votes).most_common(1)[0][0]
        if winner in ('A', 'B'):
            return winner   # highest-priority category wins

    return "tie"
